import java.awt.image.BufferedImage;
import java.awt.Color;
public class ImageTrace {
    public static void main(String[] args) {
        BufferedImage img = new BufferedImage(100, 200, BufferedImage.TYPE_INT_RGB);
        System.out.println(img.getWidth());
        System.out.println(img.getHeight());
        img.setRGB(0, 0, Color.RED.getRGB());
        int pixel = img.getRGB(0, 0);
        System.out.println(pixel == Color.RED.getRGB());
        System.out.println(img.getType() == BufferedImage.TYPE_INT_RGB);
    }
}
